@ARTICLE{10.1016/j.preteyeres.2026.101445,
	author = {Xia L and Chen L and Dai L and Zhang P, Cifuentes-González C and Gupta V and Agrawal R and Yang P},
	title = {Vogt-Koyanagi-Harada disease under the lens: Insights from multimodal ocular imaging.},
	journal = {Prog Retin Eye Res},
	year = {2026},
	abstract = {Vogt-Koyanagi-Harada (VKH) disease is a multisystem autoimmune condition targeting melanocyte-rich ocular tissues, with inflammation primarily affecting the choroid. Despite advances in diagnostic criteria, disease staging and therapeutic decisions still rely heavily on clinical observation, with limited integration of imaging biomarkers. This review examines the evolving role of multimodal ocular imaging (MMI) in the diagnosis, monitoring, and prognostication of VKH. We critically appraise the utility and limitations of color fundus photography, fluorescein angiography (FFA), indocyanine green angiography (ICGA), optical coherence tomography (OCT), OCT angiography (OCTA), fundus autofluorescence, B-scan ultrasonography, ultrasound biomicroscopy and anterior segment photography. These modalities provide complementary insights into disease activity, from subclinical choroiditis and retinal pigment epithelium disruption to chronic sequelae such as subretinal fibrosis and choroidal atrophy. Key imaging features-such as choroidal thickening, hypofluorescent dark dots, RPE undulations, and flow voids-are described in the context of VKH pathophysiology and disease stage. We identify critical gaps in current practice, including the lack of standardized imaging-based definitions for relapse and remission, limited use of anterior segment imaging, and variability in access to advanced modalities. To address these challenges, we propose a stage-specific imaging framework to guide VKH assessment from prodromal to chronic phases. MMI has transitioned from a supportive to a central role in VKH management. Future efforts should prioritize the development of quantitative imaging biomarkers, standardization of grading systems, and integration of imaging into therapeutic algorithms to support timely, personalized care and prevent irreversible visual loss.},
	doi = {10.1016/j.preteyeres.2026.101445},
	pmid = {41644040 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ajo.2025.10.028,
	author = {Samalia PD and Sims JL and Tomkins-Netzer O and Lightman SL and Niederer RL},
	title = {Sex-Related Effects on the Clinical Presentation of Uveitis.},
	journal = {Am J Ophthalmol},
	year = {2026},
	abstract = {OBJECTIVE/PURPOSE: The primary aim of this study was to determine sex-related patterns of uveitic entities. Secondary aims included sex-related patterns of uveitic complications. DESIGN: Retrospective clinical cohort study. PARTICIPANTS: 5703 participants presenting with uveitis from January 2009 to December 2023 were included. MAIN OUTCOME MEASURES: uveitis entities and complications. RESULTS: 2870 (50.3%) participants were female and 2831 (49.6%) were male. Males presented at a significantly younger age than females (42.2 vs 45.0). Significant sex-based differences were observed in the prevalence of specific uveitic conditions. Females were more likely to develop multifocal choroiditis (female: male ratio 1.818:1), Vogt-Koyanagi-Harada syndrome (female: male ratio 2.136:1), birdshot chorioretinopathy (female: male ratio 2.800:1, punctate inner choroidopathy (female: male ratio 6.571:1), drug-induced uveitis (female: male ratio 2.833:1), Crohn's disease (female: male ratio 3.714:1) and multiple evanescent white dot syndrome (female: male ratio 5.000:1). In contrast, males were more likely to develop acute posterior multifocal placoid pigment epitheliopathy (female: male ratio 0.364:1), sympathetic ophthalmia (female: male ratio 0.353:1) and syphilis (female: male ratio 0.404:1). Cataract was significantly more common in females, and this remained significant after adjusting for age at presentation, anatomical location and bilaterality. Cystoid macular edema and epiretinal membrane were more frequent in females, whereas retinal detachment occurred more often in males. Bilateral vision loss occurred in 238 patients (4.2%) and was significantly more common in females (4.9% vs 3.5%). CONCLUSIONS: Sex appears to be a key factor influencing the underlying etiology and clinical course of uveitis. These findings underscore the importance of considering sex as a biological variable in the diagnosis, monitoring, and management of uveitis.},
	doi = {10.1016/j.ajo.2025.10.028},
	pmid = {41642701 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fmed.2026.1733153,
	author = {Huang Y and Wang Y and Ren Q},
	title = {Co-occurrence of Vogt-Koyanagi-Harada disease, diabetic retinopathy, and advanced chronic kidney disease: a case report.},
	journal = {Front Med (Lausanne)},
	year = {2026},
	abstract = {OBJECTIVE: This study aimed to report a case of Vogt-Koyanagi-Harada (VKH) disease in a 53-year-old man with renal failure and diabetes, highlighting the challenges in diagnosing VKH amidst complex systemic comorbidities. METHODS: A case report was conducted through a retrospective review of the patient's medical history, clinical presentations, diagnostic workup, and treatment course. RESULTS: A 53-year-old man with renal failure, hypoalbuminemia, and diabetes presented with blurred vision. Initial findings included bilateral serous retinal detachment with subretinal septa, choroidal thickening, and left eye vitreous hemorrhage, without anterior chamber inflammation. Subsequent anterior segment inflammation and a positive response to combined corticosteroids and adalimumab confirmed VKH. CONCLUSION: This case underscores the diagnostic complexity of VKH in patients with multiple systemic conditions. Corticosteroid management in such individuals requires meticulous attention, emphasizing the need for close monitoring of blood glucose and overall systemic status during treatment.},
	doi = {10.3389/fmed.2026.1733153},
	pmid = {41640516},
	note = {PMC12864085}
}

